<?php if(!defined('ABSPATH')){exit;}global $wpdb;$user_id=get_current_user_id();$query="SELECT p.*,t.name as type_name,loc.name as location_name FROM {$wpdb->prefix}ls_wishlist w JOIN {$wpdb->prefix}ls_property p ON w.property_id = p.id LEFT JOIN {$wpdb->prefix}ls_types t ON p.type = t.id LEFT JOIN {$wpdb->prefix}ls_location loc ON p.location = loc.id WHERE w.user_id = %d ORDER BY w.created_at DESC";$listings=$wpdb->get_results($wpdb->prepare($query,$user_id)); ?><div class="lef-mp-my-wish-container"><div class="lef-mp-my-wish-header"><h2 class="lef-mp-my-wish-title">My Wishlist</h2> <?php if($listings): ?><div class="lef-mp-my-wish-actions"><button id="lef-mp-my-wish-select-toggle" class="lef-mp-my-wish-action-btn">Select</button><button id="lef-mp-my-wish-clear-all" class="lef-mp-my-wish-clear-btn">Clear All</button><button id="lef-mp-my-wish-remove-selected" class="lef-mp-my-wish-remove-btn-bulk" style="display: none;">Remove Selected (<span id="lef-mp-my-wish-selected-count">0</span>)</button></div> <?php endif; ?></div> <?php if($listings): ?><div class="lef-mp-my-wish-grid" id="lef-mp-my-wish-grid"> <?php foreach($listings as $listing):$image_data=$wpdb->get_var($wpdb->prepare("SELECT image FROM {$wpdb->prefix}ls_img WHERE property_id = %d",$listing->id));$images=array();if($image_data){$decoded_images=json_decode($image_data,true);if(is_array($decoded_images)){usort($decoded_images,function($a,$b){return $a['sort_order']-$b['sort_order'];});$images=array_column($decoded_images,'url');}}$fallback_img=lef_get_image_url('placeholder.png');if(empty($images)){$images=array($fallback_img);}$type_display=$listing->type_name?$listing->type_name:'Property';$loc_display=$listing->location_name?$listing->location_name:'Premium Location';$title=sprintf("%s in %s",$type_display,$loc_display);$title_limit=35;if(mb_strlen($title)>$title_limit){$title=mb_substr($title,0,$title_limit).'..';}$summary=sprintf("%d bedroom, %d bed",$listing->bedroom,$listing->bed);$redirect_url=lef_get_secure_detail_url($listing->id); ?><div class="lef-mp-my-wish-card" data-redirect="<?php echo esc_attr($redirect_url); ?>"><div class="lef-mp-my-wish-checkbox-container" style="display: none;"><input type="checkbox" class="lef-mp-my-wish-item-checkbox" data-id="<?php echo esc_attr($listing->id); ?>"></div><div class="lef-mp-my-wish-card-image-container" data-images='<?php echo json_encode($images); ?>' data-current="0"><img src="<?php echo esc_url($images[0]); ?>" alt="<?php echo esc_attr($title); ?>" class="lef-mp-my-wish-card-image" onerror="this.src='<?php echo esc_url($fallback_img); ?>'; this.classList.add('lef-is-placeholder');"><button class="lef-mp-my-wish-fav-btn is-active lef-mp-my-wish-remove-btn" aria-label="Remove from wishlist" data-id="<?php echo esc_attr($listing->id); ?>"><svg viewBox="0 0 24 24"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path></svg></button> <?php if(count($images)>1): ?><button class="lef-mp-my-wish-nav lef-mp-my-wish-nav-prev">❮</button><button class="lef-mp-my-wish-nav lef-mp-my-wish-nav-next">❯</button> <?php endif; ?></div><div class="lef-mp-my-wish-card-body"><h3 class="lef-mp-my-wish-card-title"><?php echo esc_html($title); ?></h3><p class="lef-mp-my-wish-card-summary"><?php echo esc_html($summary); ?></p><div class="lef-mp-my-wish-card-price"><span class="lef-mp-my-wish-price-amount">₹<?php echo esc_html($listing->price); ?></span><span class="lef-mp-my-wish-price-period">/ night</span></div></div></div> <?php endforeach; ?></div> <?php else: ?><div class="lef-mp-my-wish-empty"><p>Your wishlist is empty.</p></div> <?php endif; ?></div> 